def encode(message):
    encoded_chars = []
    vowels_lower = {'a', 'e', 'i', 'o', 'u'}
    vowels_upper = {'A', 'E', 'I', 'O', 'U'}

    for char in message:
        if not char.isalpha():
            encoded_chars.append(char)
            continue

        temp_char = char

        if char.islower() and char in vowels_lower:
            temp_char = chr(ord(char) + 2)
        elif char.isupper() and char in vowels_upper:
            temp_char = chr(ord(char) + 2)

        # Swap case of the (potentially modified) character
        if temp_char.islower():
            encoded_chars.append(temp_char.upper())
        else:
            encoded_chars.append(temp_char.lower())

    return "".join(encoded_chars)
